
.artifact-list {
  display: flex;
  flex-direction: column;
  gap: 0.6em;
}

.art-item {
  padding: 0.55em 0.7em;
  background: rgba(216, 193, 136, 0.05);
  border: 1px solid var(--c-border-gold);
  border-radius: 3px;
}

.art-head {
  display: flex;
  align-items: center;
  gap: 0.5em;

  .art-icon {
    color: var(--c-primary);
  }

  .art-id {
    flex: 1;
    min-width: 0;
  }

  .art-name {
    color: var(--c-text);
    font-size: 0.96em;
    letter-spacing: 0.04em;
  }

  .art-sub {
    font-size: 0.76em;
    color: var(--c-text-muted);
  }

  .art-status {
    margin-left: auto;
    font-size: 0.74em;
    padding: 0.05em 0.4em;
    border-radius: 2px;
    color: var(--c-primary);
    border: 1px solid var(--c-border-gold);
    background: rgba(216, 193, 136, 0.06);
  }
}

.art-effect {
  margin: 0.35em 0 0;
  font-size: 0.85em;
  line-height: 1.5;
  color: var(--c-text);
}

.art-desc {
  margin: 0.25em 0 0;
  font-size: 0.8em;
  line-height: 1.5;
  color: var(--c-text-muted);
}
