
.wx-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.55);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  padding: 0.6em;
}

.wx-modal {
  width: 100%;
  max-width: 560px;
  max-height: 92vh;
  display: flex;
  flex-direction: column;
  background: var(--c-bg-panel, #1a181d);
  border: 1px solid var(--c-border-gold, #6b5a3a);
  border-radius: 4px;
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.5);
}

.wx-modal-head {
  display: flex;
  align-items: center;
  gap: 0.4em;
  padding: 0.55em 0.7em;
  border-bottom: 1px solid var(--c-border);
  background: rgba(216, 193, 136, 0.06);

  .wx-head-icon {
    color: var(--c-primary);
  }
  .wx-modal-title {
    flex: 1;
    color: var(--c-text);
    font-size: 0.92em;
    letter-spacing: 0.04em;
  }
  .wx-modal-close {
    background: transparent;
    border: none;
    color: var(--c-text-muted);
    cursor: pointer;
    padding: 0.1em;
    display: inline-flex;
    &:hover {
      color: var(--c-text);
    }
  }
}

.wx-modal-body {
  flex: 1;
  overflow-y: auto;
  padding: 0.6em 0.7em;
  display: flex;
  flex-direction: column;
  gap: 0.7em;
}

.wx-section {
  display: flex;
  flex-direction: column;
  gap: 0.3em;
}

.wx-section-title {
  color: var(--c-primary);
  font-size: 0.84em;
  font-weight: bold;
  letter-spacing: 0.03em;
}

.wx-section-hint {
  color: var(--c-text-dim);
  font-size: 0.86em;
  font-weight: normal;
}

.wx-label {
  font-size: 0.76em;
  color: var(--c-text-dim);
  margin-top: 0.15em;
}

.wx-input,
.wx-select,
.wx-textarea {
  width: 100%;
  box-sizing: border-box;
  padding: 0.35em 0.5em;
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  color: var(--c-text);
  font-size: 0.84em;
  font-family: inherit;

  &:focus {
    outline: none;
    border-color: var(--c-primary-dim, #8a7a4a);
  }
}

.wx-textarea {
  resize: vertical;
  line-height: 1.5;
}

.wx-model-row {
  display: flex;
  gap: 0.35em;

  .wx-input {
    flex: 1;
    min-width: 0;
  }
  .wx-btn-sm {
    flex-shrink: 0;
  }
}

.wx-model-select-row {
  margin-top: 0.3em;
}

.wx-model-hint {
  margin-top: 0.3em;
  font-size: 0.74em;
  color: var(--c-warn, #d9a441);
  letter-spacing: 0.02em;
  line-height: 1.5;
}

.wx-preset-row {
  display: flex;
  gap: 0.35em;

  .wx-select {
    flex: 1;
    min-width: 0;
  }
}

.wx-search-row {
  position: relative;
  display: flex;
  align-items: center;

  .wx-search-icon {
    position: absolute;
    left: 0.45em;
    color: var(--c-text-dim);
    pointer-events: none;
  }
  .wx-search {
    padding-left: 1.6em;
  }
}

.wx-lore-selected {
  background: rgba(168, 136, 212, 0.08);
  border: 1px solid rgba(168, 136, 212, 0.3);
  border-radius: 3px;
  padding: 0.4em 0.5em;
}

.wls-head {
  display: flex;
  align-items: center;
  margin-bottom: 0.35em;
  font-size: 0.78em;

  .wls-title {
    flex: 1;
    color: var(--c-luck);
    font-weight: bold;
  }
  .wls-clear {
    background: transparent;
    border: 1px solid var(--c-border);
    color: var(--c-text-dim);
    font-size: 0.84em;
    padding: 0.05em 0.4em;
    border-radius: 2px;
    cursor: pointer;
    font-family: inherit;
    &:hover { color: var(--c-danger); border-color: var(--c-danger); }
  }
}

.wls-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.3em;
}

.wls-tag {
  display: inline-flex;
  align-items: center;
  gap: 0.25em;
  font-size: 0.74em;
  padding: 0.15em 0.4em;
  background: rgba(168, 136, 212, 0.14);
  border: 1px solid rgba(168, 136, 212, 0.4);
  border-radius: 2px;
  color: var(--c-text);
  max-width: 100%;
  cursor: default;

  .wls-remove {
    background: transparent;
    border: none;
    color: var(--c-text-dim);
    cursor: pointer;
    font-size: 1.1em;
    line-height: 1;
    padding: 0;
    &:hover { color: var(--c-danger); }
  }
}

.wx-lore-char-row {
  display: flex;
  align-items: center;
  gap: 0.5em;

  .wx-label {
    margin-top: 0;
    flex-shrink: 0;
  }
  .wx-select {
    flex: 1;
    min-width: 0;
  }
}

.wx-lore-list {
  display: flex;
  flex-direction: column;
  gap: 0.3em;
  max-height: 440px;
  overflow-y: auto;
  padding-right: 0.2em;
}

/* 工具栏 */
.wx-lore-toolbar {
  display: flex;
  gap: 0.3em;
  padding-bottom: 0.35em;
  border-bottom: 1px solid var(--c-border);
  margin-bottom: 0.15em;
}

.wx-btn-sm {
  font-size: 0.72em;
  padding: 0.2em 0.5em;
}

/* 分组 */
.wx-lore-group {
  display: flex;
  flex-direction: column;
}

.wx-lore-group-head {
  display: flex;
  align-items: center;
  gap: 0.35em;
  padding: 0.3em 0.4em;
  background: rgba(216, 193, 136, 0.08);
  border: 1px solid rgba(216, 193, 136, 0.2);
  border-radius: 3px;
  cursor: pointer;
  font-family: inherit;
  font-size: 0.78em;
  color: var(--c-text);
  text-align: left;
  width: 100%;
  transition: background 0.15s;

  &:hover {
    background: rgba(216, 193, 136, 0.15);
  }

  .wx-group-arrow {
    flex-shrink: 0;
    color: var(--c-primary);
  }

  .wx-lore-group-name {
    flex: 1;
    font-weight: bold;
    color: var(--c-primary-dim, #8a7a4a);
  }

  .wx-lore-group-stat {
    font-size: 0.9em;
    color: var(--c-text-dim);
    font-variant-numeric: tabular-nums;
  }

  .wx-lore-group-check {
    flex-shrink: 0;
    font-size: 0.85em;
    padding: 0.1em 0.45em;
    background: rgba(0,0,0,0.25);
    border: 1px solid var(--c-border);
    border-radius: 3px;
    color: var(--c-text-muted);
    cursor: pointer;
    font-family: inherit;

    &:hover {
      color: var(--c-primary);
      border-color: var(--c-primary-dim);
    }
  }
}

.wx-lore-group-body {
  display: flex;
  flex-direction: column;
  gap: 0.15em;
  padding: 0.25em 0 0.25em 1.2em;
}

.wx-lore-empty {
  color: var(--c-text-dim);
  font-size: 0.8em;
  font-style: italic;
  text-align: center;
  padding: 0.8em;
}

.wx-lore-item {
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 3px;
}

.wx-lore-label {
  display: flex;
  align-items: center;
  gap: 0.4em;
  padding: 0.35em 0.5em;
  cursor: pointer;
  margin: 0;
  font-size: 0.82em;
  color: var(--c-text);

  input[type='checkbox'] {
    cursor: pointer;
    flex-shrink: 0;
  }
  .wx-lore-name {
    flex: 1;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  .wx-lore-toggle {
    background: transparent;
    border: none;
    color: var(--c-text-dim);
    cursor: pointer;
    padding: 0 0.2em;
    display: inline-flex;
  }
}

.wx-lore-content {
  padding: 0.4em 0.6em;
  font-size: 0.76em;
  line-height: 1.5;
  color: var(--c-text-muted);
  border-top: 1px solid var(--c-border);
  max-height: 120px;
  overflow-y: auto;
  white-space: pre-wrap;
}

.wx-modal-foot {
  display: flex;
  justify-content: flex-end;
  gap: 0.4em;
  padding: 0.55em 0.7em;
  border-top: 1px solid var(--c-border);
}

.wx-btn {
  padding: 0.3em 0.7em;
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  color: var(--c-text);
  font-size: 0.8em;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  gap: 0.25em;
  font-family: inherit;

  &:hover:not(:disabled) {
    border-color: var(--c-primary-dim, #8a7a4a);
  }
  &:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }
}

.wx-btn-primary {
  background: linear-gradient(135deg, var(--c-primary, #d8c188), #b89a5a);
  color: #1a181d;
  border-color: var(--c-primary, #d8c188);
  font-weight: bold;
}

.wx-btn-danger {
  &:hover:not(:disabled) {
    border-color: var(--c-danger, #c4665b);
    color: var(--c-danger, #c4665b);
  }
}
