
.stat-bar {
  font-size: 0.86em;

  .row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: var(--c-text-muted);
  }

  .label {
    display: inline-flex;
    align-items: center;
    gap: 0.35em;
    color: var(--c-primary);
    letter-spacing: 0.04em;
  }

  .value {
    font-variant-numeric: tabular-nums;
    color: var(--c-text);

    .max {
      color: var(--c-text-dim);
      font-size: 0.85em;
    }
  }

  .track {
    margin-top: 3px;
    height: 7px;
    background: linear-gradient(180deg, rgba(0, 0, 0, 0.45), rgba(255, 255, 255, 0.03));
    border: 1px solid var(--c-border);
    border-radius: 2px;
    overflow: hidden;
    position: relative;
  }

  .fill {
    height: 100%;
    background: linear-gradient(90deg, color-mix(in srgb, var(--tone) 55%, transparent), var(--tone));
    box-shadow: 0 0 6px color-mix(in srgb, var(--tone) 60%, transparent);
    transition: width 0.5s cubic-bezier(0.25, 0.8, 0.25, 1);
    position: relative;

    &::after {
      content: '';
      position: absolute;
      inset: 0;
      background: linear-gradient(180deg, rgba(255, 255, 255, 0.35), transparent 60%);
    }
  }

  &.is-low {
    .fill {
      animation: pulse 1.6s ease-in-out infinite;
    }
    .value {
      color: var(--c-danger);
    }
  }
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.55;
  }
}
