
.partner-list {
  display: flex;
  flex-direction: column;
  gap: 0.6em;
}

.partner-item {
  display: flex;
  align-items: flex-start;
  gap: 0.5em;
  padding: 0.55em 0.7em;
  background: rgba(196, 102, 91, 0.05);
  border: 1px solid rgba(196, 102, 91, 0.25);
  border-radius: 3px;
}

.partner-thumb {
  flex-shrink: 0;
  width: 2.8em;
  height: 3.5em;
  border-radius: 3px;
  overflow: hidden;
  border: 1px solid rgba(196, 102, 91, 0.4);
  background: rgba(0, 0, 0, 0.3);
  cursor: pointer;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.15s;

  &:hover {
    transform: scale(1.05);
    border-color: var(--c-danger);
  }

  .partner-thumb-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }
}

.partner-thumb-empty {
  color: var(--c-danger);

  &:hover {
    transform: scale(1.05);
    border-color: var(--c-danger);
    color: var(--c-danger);
  }
}

.partner-main {
  flex: 1;
  min-width: 0;
}

.partner-head {
  display: flex;
  align-items: center;
  gap: 0.5em;

  .partner-id {
    flex: 0 1 auto;
    min-width: 0;
  }

  .partner-name {
    color: var(--c-text);
    font-size: 0.96em;
    letter-spacing: 0.04em;
  }

  .partner-realm {
    font-size: 0.76em;
    color: var(--c-warn);
  }

  .partner-status {
    margin-left: auto;
    font-size: 0.72em;
    padding: 0.05em 0.4em;
    border-radius: 2px;
    color: var(--c-danger);
    border: 1px solid rgba(196, 102, 91, 0.4);
    background: rgba(196, 102, 91, 0.06);
  }
}

.partner-favor {
  display: flex;
  align-items: center;
  gap: 0.5em;
  margin-top: 0.45em;
  font-size: 0.76em;
  color: var(--c-text-muted);

  .fav-track {
    flex: 1;
    height: 4px;
    background: var(--c-border);
    border-radius: 2px;
    overflow: hidden;
  }
  .fav-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--c-danger), #e08a7e);
    box-shadow: 0 0 5px rgba(196, 102, 91, 0.4);
  }
  .fav-num {
    font-variant-numeric: tabular-nums;
    color: var(--c-text);
  }
}

.partner-stats {
  display: flex;
  gap: 0.9em;
  margin-top: 0.4em;
  font-size: 0.74em;
  color: var(--c-text-dim);
  font-variant-numeric: tabular-nums;
}

.partner-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 0.3em 0.6em;
  font-size: 0.74em;
  color: var(--c-text-muted);

  .meta-tag {
    font-variant-numeric: tabular-nums;
  }
}

.partner-line {
  margin: 0.35em 0 0;
  font-size: 0.8em;
  line-height: 1.5;
  color: var(--c-text-muted);
}

.partner-char {
  color: var(--c-accent);
}

.partner-art {
  color: var(--c-warn);
}

.partner-voice {
  margin: 0.4em 0 0;
  font-size: 0.8em;
  line-height: 1.5;
  font-style: italic;
  color: var(--c-text-dim);
}

.field-label {
  display: inline-block;
  margin-right: 0.35em;
  font-size: 0.86em;
  font-style: normal;
  color: var(--c-text-dim);
  letter-spacing: 0.05em;

  &::after {
    content: ' ';
  }
}

/* 窄屏：立绘浮动，长文字环绕填进图下方空白，省行高 */
@media (max-width: 520px) {
  .partner-item { display: block; }
  .partner-thumb { float: left; margin: 0 0.6em 0.4em 0; }
  .partner-main { display: block; width: auto; overflow: visible; flex: none; }
}
