
.pet-list {
  display: flex;
  flex-direction: column;
  gap: 0.6em;
}

.pet-item {
  display: flex;
  align-items: flex-start;
  gap: 0.55em;
  padding: 0.55em 0.7em;
  background: rgba(95, 179, 196, 0.05);
  border: 1px solid rgba(95, 179, 196, 0.25);
  border-radius: 3px;
}

.pet-thumb {
  flex-shrink: 0;
  width: 2.8em;
  height: 3.5em;
  border-radius: 3px;
  overflow: hidden;
  border: 1px solid var(--c-border-gold, #6b5a3a);
  background: rgba(0, 0, 0, 0.3);
  cursor: pointer;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.15s;

  &:hover {
    transform: scale(1.05);
    border-color: var(--c-mind);
  }

  .pet-thumb-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }
}

.pet-thumb-empty {
  color: var(--c-text-dim);

  &:hover {
    transform: scale(1.05);
    border-color: var(--c-mind);
    color: var(--c-mind);
  }
}

.pet-main {
  flex: 1;
  min-width: 0;
}

.pet-head {
  display: flex;
  align-items: center;
  gap: 0.5em;

  .pet-icon {
    color: var(--c-mind);
  }

  .pet-id {
    flex: 1;
    min-width: 0;
  }

  .pet-name {
    color: var(--c-text);
    font-size: 0.96em;
    letter-spacing: 0.04em;
  }

  .pet-sub {
    display: flex;
    gap: 0.4em;
    font-size: 0.76em;
    color: var(--c-text-muted);
  }

  .pet-status {
    margin-left: auto;
    font-size: 0.74em;
    padding: 0.05em 0.4em;
    border-radius: 2px;
    color: var(--c-mind);
    border: 1px solid rgba(95, 179, 196, 0.4);
    background: rgba(95, 179, 196, 0.06);
  }
}

.pet-loyal {
  display: flex;
  align-items: center;
  gap: 0.5em;
  margin-top: 0.45em;
  font-size: 0.76em;
  color: var(--c-text-muted);

  .loyal-track {
    flex: 1;
    height: 4px;
    background: var(--c-border);
    border-radius: 2px;
    overflow: hidden;
  }
  .loyal-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--c-mind), #7fc8d6);
  }
  .loyal-num {
    font-variant-numeric: tabular-nums;
    color: var(--c-text);
  }
}

.pet-stats {
  display: flex;
  gap: 0.9em;
  margin-top: 0.4em;
  font-size: 0.74em;
  color: var(--c-text-dim);
  font-variant-numeric: tabular-nums;
}

.pet-appear,
.pet-abilities,
.pet-desc {
  margin: 0.35em 0 0;
  font-size: 0.82em;
  line-height: 1.5;
  color: var(--c-text-muted);
}

.pet-appear {
  color: var(--c-text);
}

.pet-abilities strong {
  color: var(--c-primary);
  font-weight: normal;
}

/* 窄屏：立绘浮动，长文字环绕填进图下方空白，省行高 */
@media (max-width: 520px) {
  .pet-item { display: block; }
  .pet-thumb { float: left; margin: 0 0.6em 0.4em 0; }
  .pet-main { display: block; width: auto; overflow: visible; flex: none; }
}
