
.craft-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.7em;
}

.craft-block {
  padding: 0.55em 0.65em;
  background: rgba(0, 0, 0, 0.2);
  border: 1px solid var(--c-border);
  border-radius: 3px;

  &.alchemy .cb-head .dy-icon {
    color: var(--c-accent);
  }
  &.forge .cb-head .dy-icon {
    color: var(--c-warn);
  }
}

.cb-head {
  display: flex;
  align-items: center;
  gap: 0.4em;
  color: var(--c-primary);
  font-size: 0.9em;
  letter-spacing: 0.06em;
}

.cb-rank {
  margin: 0.3em 0;
  font-size: 1em;
  color: var(--c-text);
}

.cb-stats {
  display: flex;
  flex-direction: column;
  gap: 0.15em;
  font-size: 0.76em;
  color: var(--c-text-muted);

  b {
    color: var(--c-text);
    font-variant-numeric: tabular-nums;
    font-weight: normal;
  }
}
