
.trend-list {
  display: flex;
  flex-direction: column;
  gap: 0.55em;
}

.trend-item {
  padding: 0.45em 2.2em 0.45em 0.6em;
  position: relative;
  background: rgba(95, 179, 196, 0.05);
  border: 1px solid var(--c-border);
  border-radius: 3px;
}

.trend-head {
  display: flex;
  align-items: center;
  gap: 0.5em;
  flex-wrap: wrap;

  .trend-name {
    color: var(--c-mind);
    font-size: 0.94em;
    letter-spacing: 0.04em;
  }
  .trend-type {
    font-size: 0.74em;
    color: var(--c-text-muted);
    padding: 0.02em 0.4em;
    border: 1px solid var(--c-border);
    border-radius: 2px;
  }
  .trend-phase {
    font-size: 0.7em;
    color: var(--c-warn);
    padding: 0.02em 0.4em;
    border: 1px solid rgba(217, 164, 65, 0.4);
    border-radius: 2px;
    background: rgba(217, 164, 65, 0.08);
  }
  .trend-loc {
    margin-left: auto;
    display: inline-flex;
    align-items: center;
    gap: 0.25em;
    font-size: 0.74em;
    color: var(--c-text-muted);
  }
}

.trend-desc {
  margin: 0.3em 0 0;
  font-size: 0.82em;
  line-height: 1.5;
  color: var(--c-text);
}

.del-btn {
  position: absolute;
  top: 0.35em;
  right: 0.35em;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.25em;
  line-height: 0;
  color: var(--c-text-dim);
  background: rgba(0, 0, 0, 0.3);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  cursor: pointer;
  transition: color 0.15s, background 0.15s, border-color 0.15s;

  &:hover {
    color: #f3e6d0;
    background: rgba(196, 102, 91, 0.65);
    border-color: rgba(196, 102, 91, 0.6);
  }
}
