
/* 一级：联系人列表 */
.yj-list {
  display: flex;
  flex-direction: column;
  gap: 0.2em;
}

.yj-list-settings {
  display: flex;
  align-items: center;
  gap: 0.4em;
  width: 100%;
  padding: 0.5em 0.5em;
  background: rgba(216, 193, 136, 0.08);
  border: 1px dashed var(--c-border-gold, #6b5a3a);
  border-radius: 3px;
  cursor: pointer;
  text-align: left;
  color: var(--c-primary);
  font-size: 0.84em;
  margin-bottom: 0.3em;

  span {
    flex: 1;
  }

  &:hover {
    background: rgba(216, 193, 136, 0.14);
  }

  .yj-arrow {
    color: var(--c-text-dim);
  }
}

.yj-contact {
  display: flex;
  align-items: center;
  gap: 0.55em;
  width: 100%;
  padding: 0.5em 0.4em;
  background: transparent;
  border: none;
  border-bottom: 1px solid var(--c-border);
  cursor: pointer;
  text-align: left;
  color: inherit;
  transition: background 0.15s;

  &:last-child {
    border-bottom: none;
  }
  &:hover {
    background: rgba(216, 193, 136, 0.06);
  }

  .yj-avatar {
    color: var(--c-primary-dim);
    padding: 0.15em;
    border: 1px solid var(--c-border-gold);
    border-radius: 50%;
    flex-shrink: 0;
  }

  .yj-info {
    flex: 1;
    min-width: 0;
  }

  .yj-top {
    display: flex;
    align-items: center;
    gap: 0.4em;
  }

  .yj-name {
    color: var(--c-text);
    font-size: 0.9em;
    letter-spacing: 0.04em;
  }

  .yj-rel {
    font-size: 0.68em;
    padding: 0.05em 0.35em;
    border-radius: 2px;
    color: var(--c-primary);
    border: 1px solid rgba(216, 193, 136, 0.4);
    background: rgba(216, 193, 136, 0.06);
  }

  .yj-bottom {
    margin-top: 0.15em;
    font-size: 0.74em;
    color: var(--c-text-dim);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .yj-preview {
    color: var(--c-text-muted);
  }

  .yj-no-msg {
    font-style: italic;
    color: var(--c-text-dim);
  }

  .yj-arrow {
    color: var(--c-text-dim);
    flex-shrink: 0;
  }
}

/* 二级：聊天界面 */
.yj-chat {
  display: flex;
  flex-direction: column;
  gap: 0.45em;
}

.yj-chat-head {
  display: flex;
  align-items: center;
  gap: 0.4em;
  padding-bottom: 0.4em;
  border-bottom: 1px solid var(--c-border);

  .yj-back {
    display: inline-flex;
    align-items: center;
    padding: 0.1em 0.2em;
    background: transparent;
    border: none;
    color: var(--c-text-muted);
    cursor: pointer;
  }

  .yj-chat-id {
    flex: 1;
    min-width: 0;
    display: flex;
    align-items: baseline;
    gap: 0.4em;
  }

  .yj-chat-name {
    color: var(--c-text);
    font-size: 0.94em;
    letter-spacing: 0.04em;
  }

  .yj-chat-realm {
    font-size: 0.72em;
    color: var(--c-warn);
  }

  .yj-chat-rel {
    font-size: 0.7em;
    padding: 0.05em 0.35em;
    border-radius: 2px;
    color: var(--c-primary);
    border: 1px solid rgba(216, 193, 136, 0.4);
    background: rgba(216, 193, 136, 0.06);
  }
}

.yj-favor {
  display: flex;
  align-items: center;
  gap: 0.5em;
  font-size: 0.74em;
  color: var(--c-text-muted);

  .fav-track {
    flex: 1;
    height: 4px;
    background: var(--c-border);
    border-radius: 2px;
    overflow: hidden;
  }
  .fav-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--c-primary), #e0c97a);
    box-shadow: 0 0 5px rgba(216, 193, 136, 0.4);
  }
  .fav-num {
    font-variant-numeric: tabular-nums;
    color: var(--c-text);
  }
}

.yj-messages {
  display: flex;
  flex-direction: column;
  gap: 0.5em;
  max-height: 50vh;
  overflow-y: auto;
  padding: 0.2em 0.2em 0.2em 0;
}

/* 微信式气泡：对方左、我右 */
.yj-bubble {
  display: flex;
  align-items: flex-end;
  gap: 0.3em;
  align-self: flex-start;
  max-width: 100%;

  &[data-mine='true'] {
    flex-direction: row-reverse;
    align-self: flex-end;
  }
}

.yj-bubble-main {
  max-width: 85%;
  padding: 0.35em 0.55em;
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid var(--c-border);
  border-radius: 8px;
  border-bottom-left-radius: 2px;
  position: relative;

  .yj-bubble-meta {
    display: flex;
    align-items: center;
    gap: 0.5em;
    margin-bottom: 0.15em;
    font-size: 0.7em;

    .yj-sender {
      color: var(--c-text);
    }
    .yj-time {
      color: var(--c-text-dim);
      font-variant-numeric: tabular-nums;
    }
  }

  .yj-bubble-content {
    font-size: 0.84em;
    line-height: 1.5;
    color: var(--c-text);
    word-break: break-word;
    white-space: pre-wrap;
  }
}

.yj-bubble[data-mine='true'] {
  .yj-bubble-main {
    background: rgba(168, 136, 212, 0.12);
    border-color: rgba(168, 136, 212, 0.35);
    border-radius: 8px;
    border-bottom-right-radius: 2px;

    .yj-sender {
      color: var(--c-accent);
    }
  }
}

.yj-del-btn {
  flex-shrink: 0;
  width: 1.4em;
  height: 1.4em;
  padding: 0;
  background: transparent;
  border: none;
  color: var(--c-text-dim);
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  opacity: 0.4;
  transition: opacity 0.15s, color 0.15s;

  &:hover:not(:disabled) {
    opacity: 1;
    color: var(--c-danger, #c4665b);
  }
  &:disabled {
    cursor: not-allowed;
    opacity: 0.2;
  }
}

.yj-input-area {
  display: flex;
  gap: 0.4em;
  align-items: center;
  margin-top: 0.5em;
  padding: 0.5em;
  border-top: 1px solid var(--c-border);
}

.yj-float-back {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 1.8em;
  height: 1.8em;
  flex-shrink: 0;
  padding: 0;
  background: transparent;
  border: 1px solid var(--c-border);
  border-radius: 3px;
  color: var(--c-text-muted);
  cursor: pointer;

  &:hover {
    color: var(--c-primary);
    border-color: var(--c-primary-dim);
  }
}

.yj-input {
  flex: 1;
  box-sizing: border-box;
  padding: 0.4em 0.5em;
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  color: var(--c-text);
  font-size: 0.82em;
  font-family: inherit;
  line-height: 1.4;
  resize: none;

  &:focus {
    outline: none;
    border-color: var(--c-primary-dim, #8a7a4a);
  }
  &:disabled {
    opacity: 0.5;
  }
}

.yj-send-btn {
  padding: 0.45em 0.8em;
  background: linear-gradient(135deg, var(--c-primary, #d8c188), #b89a5a);
  border: 1px solid var(--c-primary, #d8c188);
  border-radius: 3px;
  color: #1a181d;
  font-size: 0.8em;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  gap: 0.25em;
  font-weight: bold;
  flex-shrink: 0;

  &:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }
}

/* 弹出按钮 */
.yj-popout-btn {
  display: inline-flex;
  align-items: center;
  padding: 0.15em 0.3em;
  background: transparent;
  border: 1px solid var(--c-border);
  border-radius: 3px;
  color: var(--c-text-muted);
  cursor: pointer;
  margin-left: auto;

  &:hover {
    color: var(--c-primary);
    border-color: var(--c-primary-dim);
  }
}

/* 浮动聊天窗口 */
.yj-float-overlay {
  position: fixed;
  inset: 0;
  z-index: 9999;
  background: transparent;
  pointer-events: auto;
}

.yj-float-win {
  position: fixed;
  width: 420px;
  max-width: calc(100% - 1.5em);
  max-height: 80vh;
  display: flex;
  flex-direction: column;
  background: var(--c-bg-panel, #1a181d);
  border: 1px solid var(--c-primary-dim, #8a7a4a);
  border-radius: 6px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.6);
  overflow: hidden;
  z-index: 10000;
}

.yj-float-head {
  display: flex;
  align-items: center;
  gap: 0.4em;
  padding: 0.5em 0.6em;
  background: linear-gradient(180deg, rgba(216, 193, 136, 0.12), rgba(216, 193, 136, 0.04));
  border-bottom: 1px solid var(--c-border-gold, #6b5a3a);
  cursor: grab;
  user-select: none;

  &:active {
    cursor: grabbing;
  }

  .yj-float-avatar {
    color: var(--c-primary);
    flex-shrink: 0;
  }

  .yj-float-name {
    flex: 1;
    color: var(--c-text);
    font-size: 0.9em;
    letter-spacing: 0.04em;
  }

  .yj-float-realm {
    font-size: 0.72em;
    color: var(--c-warn);
  }

  .yj-float-action {
    display: inline-flex;
    align-items: center;
    padding: 0.15em 0.3em;
    background: transparent;
    border: 1px solid var(--c-border);
    border-radius: 3px;
    color: var(--c-text-muted);
    cursor: pointer;

    &:hover {
      color: var(--c-text);
      border-color: var(--c-text-dim);
    }
  }

  .yj-float-close:hover {
    color: var(--c-danger);
    border-color: var(--c-danger);
  }
}

.yj-float-body {
  flex: 1;
  display: flex;
  flex-direction: column;
  padding: 0.5em;
  min-height: 120px;
  overflow: hidden;

  .yj-messages {
    flex: 1;
    max-height: none;
  }
}
