
.inv-list {
  display: flex;
  flex-direction: column;
  gap: 0.4em;
}

.inv-item {
  padding: 0.4em 2.2em 0.4em 0.55em;
  position: relative;
  background: rgba(0, 0, 0, 0.2);
  border: 1px solid var(--c-border);
  border-radius: 3px;
}

.inv-head {
  display: flex;
  align-items: center;
  gap: 0.4em;

  .inv-icon {
    color: var(--c-primary-dim);
    flex-shrink: 0;
  }
  .inv-name {
    flex: 1;
    min-width: 0;
    color: var(--c-text);
    font-size: 0.88em;
    letter-spacing: 0.03em;
  }
  .inv-qty {
    color: var(--c-text-muted);
    font-size: 0.82em;
    font-variant-numeric: tabular-nums;
    flex-shrink: 0;
  }
}

.inv-desc {
  margin: 0.25em 0 0;
  font-size: 0.78em;
  line-height: 1.5;
  color: var(--c-text-muted);
}

.del-btn {
  position: absolute;
  top: 0.35em;
  right: 0.35em;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.25em;
  line-height: 0;
  color: var(--c-text-dim);
  background: rgba(0, 0, 0, 0.3);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  cursor: pointer;
  transition: color 0.15s, background 0.15s, border-color 0.15s;

  &:hover {
    color: #f3e6d0;
    background: rgba(196, 102, 91, 0.65);
    border-color: rgba(196, 102, 91, 0.6);
  }
}
