
.daoyuan {
  width: 100%;
  aspect-ratio: auto;
  max-height: 1400px;
  display: flex;
  flex-direction: column;
  gap: 0.6em;
  padding: 0.7em;
  color: var(--c-text);
  border: 1px solid var(--c-border-gold);
  border-radius: 6px;
  box-shadow:
    0 0 0 1px rgba(0, 0, 0, 0.4),
    0 8px 24px rgba(0, 0, 0, 0.4);
  box-sizing: border-box;

  &.collapsed {
    aspect-ratio: auto;
    max-height: none;
    min-height: 0;
    gap: 0;
  }
}

.loading {
  align-items: center;
  justify-content: center;
  gap: 0.8em;
  color: var(--c-text-muted);
  font-style: italic;

  .spin {
    color: var(--c-primary);
    animation: spin 2.4s linear infinite;
  }
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

.tabnav {
  display: flex;
  gap: 0.2em;
  padding: 0.25em;
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid var(--c-border);
  border-radius: 4px;
  flex-wrap: wrap;
  flex-shrink: 0;

  .tab {
    flex: 1 1 auto;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.3em;
    padding: 0.3em 0.5em;
    font-family: inherit;
    font-size: 0.8em;
    color: var(--c-text-muted);
    background: transparent;
    border: none;
    border-bottom: 2px solid transparent;
    cursor: pointer;
    white-space: nowrap;
    transition: color 0.2s, border-color 0.2s, background 0.2s;
    letter-spacing: 0.04em;

    &:hover {
      color: var(--c-text);
    }
    &.active {
      color: var(--c-primary);
      border-bottom-color: var(--c-primary);
      background: linear-gradient(180deg, rgba(216, 193, 136, 0.1), transparent);
    }

    .tab-count {
      font-size: 0.72em;
      font-weight: 600;
      color: var(--c-primary);
      background: rgba(216, 193, 136, 0.12);
      border-radius: 8px;
      padding: 0.05em 0.4em;
      min-width: 1.2em;
      text-align: center;
      line-height: 1.4;
    }
  }
}

.tabbody {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  padding-right: 0.2em;
}

.tabs-expand-bar {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4em;
  width: 100%;
  padding: 0.5em;
  background: rgba(0, 0, 0, 0.2);
  border: 1px solid var(--c-border);
  border-radius: 4px;
  color: var(--c-text-muted);
  font-family: inherit;
  font-size: 0.8em;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: color 0.2s, border-color 0.2s, background 0.2s;

  &:hover {
    color: var(--c-primary);
    border-color: var(--c-border-gold);
    background: rgba(216, 193, 136, 0.06);
  }
}

/* —— 窄屏（手机）适配 —— */
@media (max-width: 520px) {
  .daoyuan {
    /* 内容驱动高度 + max-height 上限：内容少时随主角面板，多时不超过屏幕 */
    max-height: 80em;
    gap: 0.5em;
    padding: 0.6em;
  }

  .tabnav {
    flex-wrap: nowrap;
    flex-shrink: 0;
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
    padding: 0.2em;

    &::-webkit-scrollbar {
      display: none;
    }

    .tab {
      flex: 0 0 auto;
      padding: 0.5em 0.75em;
      font-size: 0.85em;
    }
  }

  .tabbody {
    /* 内容驱动高度，超出滚动；不再强制 min-height */
    flex: 1 1 auto;
    min-height: 0;
  }
}
