
.settings-overlay {
  position: fixed;
  inset: 0;
  z-index: 1000;
  background: rgba(0, 0, 0, 0.55);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1em;
}

.settings-modal {
  width: min(440px, 100%);
  max-height: 90vh;
  display: flex;
  flex-direction: column;
  background:
    linear-gradient(180deg, rgba(216, 193, 136, 0.06), transparent 30%),
    var(--c-surface);
  border: 1px solid var(--c-border-gold);
  border-radius: 6px;
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.6);
}

.settings-head {
  display: flex;
  align-items: center;
  gap: 0.5em;
  padding: 0.7em 0.9em;
  border-bottom: 1px solid var(--c-border);
  background: linear-gradient(90deg, rgba(216, 193, 136, 0.06), transparent 60%);

  .head-icon {
    color: var(--c-primary);
  }
  .settings-title {
    flex: 1;
    color: var(--c-primary);
    font-size: 1em;
    letter-spacing: 0.06em;
  }
  .settings-close {
    background: transparent;
    border: none;
    color: var(--c-text-muted);
    cursor: pointer;
    padding: 0.2em;
    display: inline-flex;
    &:hover {
      color: var(--c-text);
    }
  }
}

.settings-body {
  flex: 1;
  overflow-y: auto;
  padding: 0.8em 0.9em;
  display: flex;
  flex-direction: column;
  gap: 1em;
}

.settings-section {
  background: rgba(0, 0, 0, 0.2);
  border: 1px solid var(--c-border);
  border-radius: 4px;
  padding: 0.6em 0.7em;

  .section-title {
    color: var(--c-primary);
    font-size: 0.9em;
    letter-spacing: 0.05em;
    display: flex;
    align-items: baseline;
    gap: 0.5em;
  }
  .section-hint {
    color: var(--c-text-dim);
    font-size: 0.76em;
    margin: 0.2em 0 0.5em;
  }
}

.toggle-row {
  display: grid;
  grid-template-columns: 1fr auto;
  grid-template-rows: auto auto;
  gap: 0.1em 0.6em;
  align-items: center;
  padding: 0.45em 0;
  cursor: pointer;

  .toggle-label {
    color: var(--c-text);
    font-size: 0.86em;
  }
  .toggle-desc {
    grid-column: 1;
    color: var(--c-text-dim);
    font-size: 0.74em;
    line-height: 1.4;
  }
  .toggle-check {
    grid-column: 2;
    grid-row: 1 / span 2;
    width: 16px;
    height: 16px;
    accent-color: var(--c-primary);
    cursor: pointer;
  }
}

.tab-toolbar {
  display: flex;
  gap: 0.5em;
  margin-bottom: 0.5em;

  .tab-tool-btn {
    padding: 0.2em 0.7em;
    font-size: 0.76em;
    font-family: inherit;
    color: var(--c-text-muted);
    background: transparent;
    border: 1px solid var(--c-border);
    border-radius: 3px;
    cursor: pointer;
    &:hover {
      color: var(--c-primary);
      border-color: var(--c-border-gold);
    }
  }
}

.tab-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 0.3em 0.5em;
}

.tab-check-row {
  display: flex;
  align-items: center;
  gap: 0.4em;
  padding: 0.3em 0.4em;
  border-radius: 3px;
  cursor: pointer;
  font-size: 0.82em;
  color: var(--c-text);

  &:hover {
    background: rgba(216, 193, 136, 0.06);
  }
  input[type='checkbox'] {
    width: 14px;
    height: 14px;
    accent-color: var(--c-primary);
    cursor: pointer;
  }
  .tab-check-icon {
    color: var(--c-text-muted);
  }
}

.settings-foot {
  display: flex;
  gap: 0.5em;
  justify-content: flex-end;
  padding: 0.6em 0.9em;
  border-top: 1px solid var(--c-border);

  .foot-btn {
    display: inline-flex;
    align-items: center;
    gap: 0.3em;
    padding: 0.4em 1em;
    font-family: inherit;
    font-size: 0.84em;
    color: var(--c-text-muted);
    background: transparent;
    border: 1px solid var(--c-border);
    border-radius: 3px;
    cursor: pointer;
    &:hover {
      color: var(--c-text);
      border-color: var(--c-border-gold);
    }
    &.foot-btn-primary {
      color: var(--c-primary);
      border-color: var(--c-border-gold);
      background: rgba(216, 193, 136, 0.08);
    }
  }
}
