
.gongfa-list {
  display: flex;
  flex-direction: column;
  gap: 0.6em;
}

.gf-item {
  padding: 0.5em 0.65em;
  background: rgba(216, 193, 136, 0.04);
  border: 1px solid var(--c-border);
  border-radius: 3px;
}

.gf-head {
  display: flex;
  align-items: center;
  gap: 0.45em;
  flex-wrap: wrap;

  .gf-name {
    color: var(--c-primary);
    font-size: 0.96em;
    letter-spacing: 0.04em;
  }
  .gf-tag {
    font-size: 0.74em;
    color: var(--c-text-muted);
    padding: 0.03em 0.4em;
    border: 1px solid var(--c-border);
    border-radius: 2px;
  }
  .gf-realm {
    color: var(--c-warn);
    border-color: rgba(217, 164, 65, 0.4);
  }
}

.gf-prof {
  display: flex;
  align-items: center;
  gap: 0.5em;
  margin-top: 0.4em;
  font-size: 0.76em;
  color: var(--c-text-muted);

  .prof-track {
    flex: 1;
    height: 4px;
    background: var(--c-border);
    border-radius: 2px;
    overflow: hidden;
  }
  .prof-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--c-primary-dim), var(--c-primary));
  }
  .prof-num {
    font-variant-numeric: tabular-nums;
    color: var(--c-text);
  }
}

.gf-desc {
  margin: 0.35em 0 0;
  font-size: 0.82em;
  line-height: 1.5;
  color: var(--c-text-muted);
}
