
.portrait-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.65);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1100;
  padding: 0.6em;
}

.portrait-modal {
  width: 100%;
  max-width: 360px;
  background: var(--c-bg-panel, #1a181d);
  border: 1px solid var(--c-border-gold, #6b5a3a);
  border-radius: 4px;
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.5);
  overflow: hidden;
}

.portrait-modal-head {
  display: flex;
  align-items: center;
  padding: 0.55em 0.7em;
  border-bottom: 1px solid var(--c-border);
  background: rgba(216, 193, 136, 0.06);

  .portrait-title {
    flex: 1;
    color: var(--c-text);
    font-size: 0.92em;
    letter-spacing: 0.04em;
  }
  .portrait-close {
    background: transparent;
    border: none;
    color: var(--c-text-muted);
    cursor: pointer;
    padding: 0.1em;
    display: inline-flex;
    &:hover { color: var(--c-text); }
  }
}

.portrait-modal-body {
  padding: 0.6em;
  display: flex;
  flex-direction: column;
  gap: 0.5em;
}

.portrait-display {
  width: 100%;
  max-height: 50vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.3);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  overflow: hidden;
}

.portrait-img {
  max-width: 100%;
  max-height: 50vh;
  object-fit: contain;
}

.portrait-img-err {
  padding: 1.5em;
  color: var(--c-text-dim);
  font-size: 0.84em;
  font-style: italic;
}

.portrait-source {
  display: flex;
  justify-content: center;
  gap: 0.4em;

  .src-tag {
    font-size: 0.72em;
    padding: 0.05em 0.5em;
    border-radius: 2px;

    &.custom {
      color: var(--c-accent);
      border: 1px solid rgba(168, 136, 212, 0.4);
      background: rgba(168, 136, 212, 0.06);
    }
    &.builtin {
      color: var(--c-primary);
      border: 1px solid rgba(216, 193, 136, 0.4);
      background: rgba(216, 193, 136, 0.06);
    }
    &.special {
      color: var(--c-danger, #c4665b);
      border: 1px solid rgba(196, 102, 91, 0.4);
      background: rgba(196, 102, 91, 0.08);
    }
  }
}

// 多套立绘缩略图行
.portrait-set-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.35em;
  justify-content: center;
  padding: 0.3em 0;
  border-top: 1px dashed var(--c-border);
}

.portrait-set-thumb {
  position: relative;
  width: 3.2em;
  height: 4.2em;
  padding: 0;
  background: rgba(0, 0, 0, 0.3);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  overflow: hidden;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;

  img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  &:hover {
    border-color: var(--c-primary-dim, #8a7a4a);
  }
  &.active {
    border-color: var(--c-primary, #d8c188);
    box-shadow: 0 0 0 1px var(--c-primary, #d8c188);
  }

  .set-thumb-err {
    position: absolute;
    color: var(--c-text-dim);
    font-size: 0.9em;
  }
}

.portrait-custom-area {
  display: flex;
  flex-direction: column;
  gap: 0.4em;
  padding-top: 0.4em;
  border-top: 1px dashed var(--c-border);
}

.portrait-toggle-row {
  display: flex;
}

// 无特殊立绘提示
.portrait-empty-hint {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.3em;
  width: 100%;
  padding: 0.35em;
  border: 1px dashed var(--c-border);
  border-radius: 3px;
  color: var(--c-text-dim);
  font-size: 0.78em;
  opacity: 0.7;
}

.portrait-toggle-btn {
  width: 100%;
  justify-content: center;
  background: rgba(168, 136, 212, 0.08);
  border-color: rgba(168, 136, 212, 0.35);
  color: var(--c-accent, #a888d4);

  &:hover:not(:disabled) {
    background: rgba(168, 136, 212, 0.16);
    border-color: var(--c-accent, #a888d4);
  }
  &.active {
    background: rgba(168, 136, 212, 0.18);
    border-color: var(--c-accent, #a888d4);
  }
}

// 特殊立绘按钮用 danger 色系区分
.portrait-special-btn {
  background: rgba(196, 102, 91, 0.08);
  border-color: rgba(196, 102, 91, 0.35);
  color: var(--c-danger, #c4665b);

  &:hover:not(:disabled) {
    background: rgba(196, 102, 91, 0.16);
    border-color: var(--c-danger, #c4665b);
  }
  &.active {
    background: rgba(196, 102, 91, 0.18);
    border-color: var(--c-danger, #c4665b);
  }
}

.portrait-file-label {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.3em;
  padding: 0.4em;
  background: rgba(216, 193, 136, 0.08);
  border: 1px dashed var(--c-border-gold, #6b5a3a);
  border-radius: 3px;
  color: var(--c-primary);
  font-size: 0.82em;
  cursor: pointer;

  &:hover { background: rgba(216, 193, 136, 0.14); }

  .portrait-file-input {
    display: none;
  }
}

.portrait-url-row {
  display: flex;
  gap: 0.35em;

  .portrait-url-input {
    flex: 1;
    min-width: 0;
    padding: 0.35em 0.5em;
    background: rgba(0, 0, 0, 0.25);
    border: 1px solid var(--c-border);
    border-radius: 3px;
    color: var(--c-text);
    font-size: 0.82em;
    font-family: inherit;

    &:focus {
      outline: none;
      border-color: var(--c-primary-dim, #8a7a4a);
    }
  }
}

.portrait-btn {
  padding: 0.35em 0.6em;
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  color: var(--c-text);
  font-size: 0.8em;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  gap: 0.25em;
  font-family: inherit;

  &:hover:not(:disabled) {
    border-color: var(--c-primary-dim, #8a7a4a);
  }
  &:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }
}

.portrait-btn-danger {
  &:hover:not(:disabled) {
    border-color: var(--c-danger, #c4665b);
    color: var(--c-danger, #c4665b);
  }
}
